const lv_image_dsc_t * get_object_type_icon(const int type_num) {
    const lv_image_dsc_t * result = nullptr;
    if (type_num >= 0) {
        for (int i = 0; i < 22; i++) {
            if (object_type_icon_num[i] == type_num) {
                result = &object_type_icon_dsc[i];
                break;
            }
        }
    }
    return result;
}
